    if language == Language.VIETNAMESE:
        try:
            return VietnameseExtractor()
        except ImportError:
            logger.warning("underthesea not available — falling back to SimpleExtractor")
            return SimpleExtractor()
    try:
        return EnglishExtractor(model_name=spacy_model)
    except ImportError:
        logger.warning("spaCy not available — falling back to SimpleExtractor")
        return SimpleExtractor()

"""Entity resolution — merging duplicate entity mentions into canonical nodes."""

import logging
from typing import Any

import numpy as np

logger = logging.getLogger(__name__)


class EntityResolver:
    """Resolves duplicate entities using embedding similarity or string matching."""

    def __init__(
        self,
        threshold: float = 0.80,
        method: str = "embedding",
    ) -> None:
        self.threshold = threshold
        self.method = method
        self._embedder = None

    @property
    def embedder(self):
        """Lazy-load the sentence transformer model."""
        if self._embedder is None:
            try:
                from sentence_transformers import SentenceTransformer
                # Multilingual model — covers English + Vietnamese
                self._embedder = SentenceTransformer(
                    "paraphrase-multilingual-MiniLM-L12-v2"
                )
            except ImportError:
                logger.warning("sentence-transformers not installed — falling back to string matching")
                return None
        return self._embedder

    def resolve(self, entities: list[dict[str, Any]]) -> list[dict[str, Any]]:
        """Merge duplicate entities, returning canonical set."""
        if not entities:
            return []

        if self.method == "embedding" and self.embedder is not None:
            return self._embedding_resolve(entities)
        return self._string_resolve(entities)

    def _embedding_resolve(self, entities: list[dict[str, Any]]) -> list[dict[str, Any]]:
        """Cluster entities by embedding similarity."""
        names = [e["name"] for e in entities]
        embeddings = self.embedder.encode(names, show_progress_bar=False)

        # Greedy clustering
        clusters: list[list[int]] = []
        assigned: set[int] = set()

        for i in range(len(names)):
            if i in assigned:
                continue
            cluster = [i]
            assigned.add(i)
            for j in range(i + 1, len(names)):
                if j in assigned:
                    continue
                sim = float(np.dot(embeddings[i], embeddings[j]) / (
                    np.linalg.norm(embeddings[i]) * np.linalg.norm(embeddings[j])
                ))
                if sim >= self.threshold:
                    cluster.append(j)
                    assigned.add(j)
            clusters.append(cluster)

        # Merge each cluster into a canonical entity
        resolved: list[dict[str, Any]] = []
        for cluster in clusters:
            canonical = self._merge_cluster(entities, cluster)
            resolved.append(canonical)

        logger.info(f"Entity resolution: {len(entities)} -> {len(resolved)} unique entities")
        return resolved

    def _string_resolve(self, entities: list[dict[str, Any]]) -> list[dict[str, Any]]:
        """Resolve by normalized string similarity (no embedding deps)."""
        resolved: list[dict[str, Any]] = []
        seen: list[str] = []

        for entity in entities:
            name = entity["name"].lower().strip()
            matched = False

            for i, existing in enumerate(seen):
                if self._string_similarity(name, existing) >= self.threshold:
                    # Merge into existing
                    resolved[i]["mentions"] = list(set(
                        resolved[i].get("mentions", []) + entity.get("mentions", [name])
                    ))
                    resolved[i]["confidence"] = max(
                        resolved[i].get("confidence", 0), entity.get("confidence", 0)
                    )
                    matched = True
                    break

            if not matched:
                seen.append(name)
                resolved.append(dict(entity))

        logger.info(f"String resolution: {len(entities)} -> {len(resolved)} unique entities")
        return resolved

    def _merge_cluster(
        self, entities: list[dict[str, Any]], cluster: list[int]
    ) -> dict[str, Any]:
        """Merge a cluster of entity dicts into one canonical entity."""
        cluster_entities = [entities[i] for i in cluster]

        # Use the most common name, or the one with highest confidence
        best = max(cluster_entities, key=lambda e: (e.get("confidence", 0), len(e.get("name", ""))))

        all_mentions = []
        all_attrs: dict[str, Any] = {}
        for e in cluster_entities:
            all_mentions.extend(e.get("mentions", [e["name"]]))
            all_attrs.update(e.get("attributes", {}))

        return {
            "name": best["name"],
            "label": best.get("label", "ENTITY"),
            "mentions": list(set(all_mentions)),
            "attributes": all_attrs,
            "confidence": max(e.get("confidence", 0) for e in cluster_entities),
        }

    @staticmethod
    def _string_similarity(a: str, b: str) -> float:
        """Simple token-overlap similarity between two strings."""
        tokens_a = set(a.split())
        tokens_b = set(b.split())
        if not tokens_a or not tokens_b:
            return 0.0
        return len(tokens_a & tokens_b) / len(tokens_a | tokens_b)

"""Graph construction from resolved entities and triples."""

import logging
from typing import Any

import networkx as nx

from kg_generator.config import GraphBackend, Ontology

logger = logging.getLogger(__name__)


class GraphBuilder:
    """Builds a knowledge graph from entities and relation triples."""

    def __init__(
        self,
        ontology: Ontology | None = None,
        backend: GraphBackend = GraphBackend.NETWORKX,
    ) -> None:
        self.ontology = ontology
        self.backend = backend

    def build(
        self,
        entities: list[dict[str, Any]],
        triples: list[tuple[str, str, str]],
    ) -> nx.DiGraph:
        """Build a directed graph from entities and (subject, predicate, object) triples."""
        graph = nx.DiGraph()

        # Add entity nodes
        for entity in entities:
            graph.add_node(
                entity["name"],
                label=entity.get("label", "ENTITY"),
                confidence=entity.get("confidence", 1.0),
                mentions=entity.get("mentions", []),
                attributes=entity.get("attributes", {}),
            )

        # Add relation edges
        for subj, pred, obj in triples:
            # Ensure both endpoints exist as nodes
            if subj not in graph:
                graph.add_node(subj, label="ENTITY")
            if obj not in graph:
                graph.add_node(obj, label="ENTITY")

            # Add or update the edge
            if graph.has_edge(subj, obj):
                # Append to list of predicates
                existing = graph.edges[subj, obj].get("predicates", [])
                if pred not in existing:
                    existing.append(pred)
                graph.edges[subj, obj]["predicates"] = existing
                graph.edges[subj, obj]["weight"] = len(existing)
            else:
                graph.add_edge(
                    subj, obj,
                    predicates=[pred],
                    weight=1,
                )

        logger.info(
            f"Built graph: {graph.number_of_nodes()} nodes, {graph.number_of_edges()} edges"
        )

        # Validate against ontology if provided
        if self.ontology:
            self._validate(graph)

        return graph

    def _validate(self, graph: nx.DiGraph) -> None:
        """Check graph consistency against the ontology schema."""
        if not self.ontology:
            return

        ontology_labels = set(self.ontology.entity_types.keys())
        ontology_relations = set(self.ontology.relationship_types.keys())

        node_label_mismatches = 0
        edge_relation_mismatches = 0

        for _, data in graph.nodes(data=True):
            label = data.get("label", "")
            if label and label not in ontology_labels:
                node_label_mismatches += 1

        for _, _, data in graph.edges(data=True):
            predicates = data.get("predicates", [])
            for p in predicates:
                if p not in ontology_relations:
                    edge_relation_mismatches += 1

        if node_label_mismatches:
            logger.warning(f"Ontology validation: {node_label_mismatches} node labels not in schema")
        if edge_relation_mismatches:
            logger.warning(f"Ontology validation: {edge_relation_mismatches} relation types not in schema")

    def stats(self, graph: nx.DiGraph) -> dict[str, Any]:
        """Return summary statistics for the graph."""
        return {
            "num_nodes": graph.number_of_nodes(),
            "num_edges": graph.number_of_edges(),
            "density": nx.density(graph),
            "num_connected_components": nx.number_weakly_connected_components(graph),
            "avg_degree": sum(dict(graph.degree()).values()) / max(graph.number_of_nodes(), 1),
            "label_distribution": self._label_distribution(graph),
            "relation_distribution": self._relation_distribution(graph),
        }

    @staticmethod
    def _label_distribution(graph: nx.DiGraph) -> dict[str, int]:
        dist: dict[str, int] = {}
        for _, data in graph.nodes(data=True):
            label = data.get("label", "UNKNOWN")
            dist[label] = dist.get(label, 0) + 1
        return dist

    @staticmethod
    def _relation_distribution(graph: nx.DiGraph) -> dict[str, int]:
        dist: dict[str, int] = {}
        for _, _, data in graph.edges(data=True):
            for pred in data.get("predicates", []):
                dist[pred] = dist.get(pred, 0) + 1
        return dist

